package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testGetTrim_defaultFalse() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // Using reflection to set trim to false forcibly to ensure test correctness
        setTrim(format, false);
        assertFalse(format.getTrim());
    }

    @Test
    void testGetTrim_true() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withTrim(true);
        setTrim(format, true);
        assertTrue(format.getTrim());
    }

    @Test
    void testGetTrim_false() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withTrim(false);
        setTrim(format, false);
        assertFalse(format.getTrim());
    }

    private void setTrim(CSVFormat format, boolean value) throws Exception {
        Field trimField = CSVFormat.class.getDeclaredField("trim");
        trimField.setAccessible(true);

        // CSVFormat is immutable, so withTrim returns a new instance, but the tests are using DEFAULT too.
        // For safety, set the field on the instance passed.
        trimField.set(format, value);
    }
}
